     1→/**
     2→ * partySync.ts
     3→ *
     4→ * When a party record is edited (name, address, GSTIN, site, etc.), every
     5→ * denormalized copy of that data across related Firestore collections must be
     6→ * updated so PartyDetailView still finds the records under the new name.
     7→ *
     8→ * Collections updated:
     9→ *   ledger_entries      — party_name, address, site
    10→ *   transactions        — party_name
    11→ *   misc_charges        — party_name, party_id
    12→ *   recurring_templates — party_name
    13→ *
    14→ * The update runs as a background operation after the party doc itself is
    15→ * saved.  Firestore batches are limited to 500 ops; we chunk in groups of 400.
    16→ */
    17→
    18→import {
    19→  collection,
    20→  query,
    21→  where,
    22→  getDocs,
    23→  writeBatch,
    24→  doc as fsDoc,
    25→} from 'firebase/firestore';
    26→import { db } from '../config/firebase';
    27→import { queryClient } from '../context/DataContext';
    28→
    29→const BATCH_CHUNK = 400;
    30→
    31→interface UpdatedPartyFields {
    32→  name: string;
    33→  address?: string;
    34→  site?: string;
    35→  gstin?: string;
    36→  contact?: string;
    37→  state?: string;
    38→}
    39→
    40→/** Commit an array of [docRef, partialUpdate] in chunked batches. */
    41→async function flushUpdates(updates: Array<[any, Record<string, any>]>): Promise<void> {
    42→  for (let i = 0; i < updates.length; i += BATCH_CHUNK) {
    43→    const batch = writeBatch(db);
    44→    updates.slice(i, i + BATCH_CHUNK).forEach(([ref, data]) => batch.update(ref, data));
    45→    await batch.commit();
    46→  }
    47→}
    48→
    49→/**
    50→ * Cascade a party edit to all denormalized copies in related collections.
    51→ *
    52→ * @param uid          Firebase user UID
    53→ * @param partyId      Firestore document ID of the party
    54→ * @param oldName      The party name BEFORE the edit (used to query existing records)
    55→ * @param updated      The new field values from the edited party form
    56→ * @returns            Total number of sub-documents updated
    57→ */
    58→export async function syncPartyToRecords(
    59→  uid: string,
    60→  partyId: string,
    61→  oldName: string,
    62→  updated: UpdatedPartyFields,
    63→): Promise<number> {
    64→  const newName = updated.name;
    65→  let totalUpdated = 0;
    66→
    67→  // ── 1. ledger_entries ────────────────────────────────────────────────────
    68→  // Query by BOTH party_id (preferred, stable) AND party_name (legacy/fallback)
    69→  // so records without party_id are still updated by name.
    70→  // Each updated record also gets party_id stamped, so future cascades
    71→  // can use the ID-based path reliably.
    72→  try {
    73→    const col = collection(db, `users/${uid}/ledger_entries`);
    74→    const [byNameSnap, byIdSnap] = await Promise.all([
    75→      getDocs(query(col, where('party_name', '==', oldName))),
    76→      getDocs(query(col, where('party_id', '==', partyId))),
    77→    ]);
    78→    const seen = new Set<string>();
    79→    const allDocs = [...byNameSnap.docs, ...byIdSnap.docs].filter(d => {
    80→      if (seen.has(d.id)) return false;
    81→      seen.add(d.id);
    82→      return true;
    83→    });
    84→    if (allDocs.length > 0) {
    85→      const updates: Array<[any, Record<string, any>]> = allDocs.map(d => {
    86→        const fields: Record<string, any> = { party_name: newName, party_id: partyId };
    87→        if (updated.address !== undefined) fields.address = updated.address;
    88→        if (updated.site    !== undefined) fields.site    = updated.site;
    89→        return [fsDoc(db, `users/${uid}/ledger_entries`, d.id), fields];
    90→      });
    91→      await flushUpdates(updates);
    92→      totalUpdated += updates.length;
    93→    }
    94→  } catch (e) {
    95→    console.error('[partySync] ledger_entries update failed:', e);
    96→  }
    97→
    98→  // ── 2. transactions ──────────────────────────────────────────────────────
    99→  try {
   100→    const col = collection(db, `users/${uid}/transactions`);
   101→    const [byNameSnap, byIdSnap] = await Promise.all([
   102→      getDocs(query(col, where('party_name', '==', oldName))),
   103→      getDocs(query(col, where('party_id', '==', partyId))),
   104→    ]);
   105→    const seen = new Set<string>();
   106→    const allDocs = [...byNameSnap.docs, ...byIdSnap.docs].filter(d => {
   107→      if (seen.has(d.id)) return false;
   108→      seen.add(d.id);
   109→      return true;
   110→    });
   111→    if (allDocs.length > 0) {
   112→      const updates: Array<[any, Record<string, any>]> = allDocs.map(d => [
   113→        fsDoc(db, `users/${uid}/transactions`, d.id),
   114→        { party_name: newName, party_id: partyId },
   115→      ]);
   116→      await flushUpdates(updates);
   117→      totalUpdated += updates.length;
   118→    }
   119→  } catch (e) {
   120→    console.error('[partySync] transactions update failed:', e);
   121→  }
   122→
   123→  // ── 3. misc_charges ──────────────────────────────────────────────────────
   124→  // Misc charges are linked by party_id OR party_name — update both fields
   125→  // so future lookups by either key still find the record.
   126→  try {
   127→    const col = collection(db, `users/${uid}/misc_charges`);
   128→    // No composite index available → fetch all, filter in JS
   129→    const snap = await getDocs(col);
   130→    const toUpdate = snap.docs.filter(d => {
   131→      const data = d.data() as any;
   132→      return data.party_id === partyId || data.party_name === oldName;
   133→    });
   134→    if (toUpdate.length > 0) {
   135→      const updates: Array<[any, Record<string, any>]> = toUpdate.map(d => [
   136→        fsDoc(db, `users/${uid}/misc_charges`, d.id),
   137→        { party_name: newName, party_id: partyId },
   138→      ]);
   139→      await flushUpdates(updates);
   140→      totalUpdated += updates.length;
   141→    }
   142→  } catch (e) {
   143→    console.error('[partySync] misc_charges update failed:', e);
   144→  }
   145→
   146→  // ── 4. recurring_templates ───────────────────────────────────────────────
   147→  try {
   148→    const col = collection(db, `users/${uid}/recurring_templates`);
   149→    const [byNameSnap, byIdSnap] = await Promise.all([
   150→      getDocs(query(col, where('party_name', '==', oldName))),
   151→      getDocs(query(col, where('party_id', '==', partyId))),
   152→    ]);
   153→    const seen = new Set<string>();
   154→    const allDocs = [...byNameSnap.docs, ...byIdSnap.docs].filter(d => {
   155→      if (seen.has(d.id)) return false;
   156→      seen.add(d.id);
   157→      return true;
   158→    });
   159→    if (allDocs.length > 0) {
   160→      const updates: Array<[any, Record<string, any>]> = allDocs.map(d => [
   161→        fsDoc(db, `users/${uid}/recurring_templates`, d.id),
   162→        { party_name: newName, party_id: partyId },
   163→      ]);
   164→      await flushUpdates(updates);
   165→      totalUpdated += updates.length;
   166→    }
   167→  } catch (e) {
   168→    console.error('[partySync] recurring_templates update failed:', e);
   169→  }
   170→
   171→  // ── 5. Invalidate TanStack Query caches ──────────────────────────────────
   172→  // Force a fresh read from Firestore so any open PartyDetailView
   173→  // immediately gets the renamed party_name instead of the stale cached copy.
   174→  try {
   175→    queryClient.invalidateQueries({ queryKey: ['ledger', uid], exact: true });
   176→    queryClient.invalidateQueries({ queryKey: ['transactions', uid], exact: true });
   177→  } catch (_) {}
   178→
   179→  return totalUpdated;
   180→}
