     1→import React, { createContext, useContext, ReactNode, useMemo, useEffect } from 'react';
     2→import { QueryClient, useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
     3→import { PersistQueryClientProvider } from '@tanstack/react-query-persist-client';
     4→import { createAsyncStoragePersister } from '@tanstack/query-async-storage-persister';
     5→import { ApiService } from '../services/api';
     6→import { Party, InventoryItem, WasteEntry } from '../types/models';
     7→import { indexedDBStorage } from '../services/queryPersistStorage';
     8→import { useUI } from './UIContext';
     9→import { parseDateSafe } from '../utils/dateUtils';
    10→
    11→// Per-collection stale windows (ms).
    12→// High-churn data (ledger, transactions, waste) use a short window.
    13→// Low-churn reference data (parties, inventory) can be cached longer.
    14→const STALE = {
    15→  SHORT:  1000 * 60 * 2,   // 2 min  — transactions, ledger, waste
    16→  MEDIUM: 1000 * 60 * 10,  // 10 min — inventory
    17→  LONG:   1000 * 60 * 20,  // 20 min — parties (rarely change)
    18→} as const;
    19→
    20→// Persist the cache for 7 days so a shopkeeper who's been offline for a few
    21→// days still cold-starts with their full inventory/ledger/parties on screen.
    22→// gcTime MUST be ≥ persister.maxAge or React Query will gc data before the
    23→// persister gets to write it.
    24→const CACHE_MAX_AGE = 1000 * 60 * 60 * 24 * 7; // 7 days
    25→
    26→const queryClient = new QueryClient({
    27→  defaultOptions: {
    28→    queries: {
    29→      staleTime: STALE.SHORT,
    30→      gcTime: CACHE_MAX_AGE,
    31→      retry: 2,
    32→      refetchOnWindowFocus: false,
    33→      refetchOnReconnect: true, // re-sync when network comes back
    34→      // When offline, NEVER mark a query as failed just because the network is
    35→      // down — keep serving the persisted IndexedDB data and let the React
    36→      // Query 'online' listener auto-refetch when we're back up. Without this
    37→      // an offline cold-start would put queries in error state immediately.
    38→      networkMode: 'offlineFirst',
    39→    },
    40→    mutations: {
    41→      networkMode: 'offlineFirst',
    42→    },
    43→  },
    44→});
    45→
    46→// IndexedDB-backed persister. Reads + writes the entire (dehydrated) query
    47→// cache as a single JSON blob. With idb-keyval this is async and out-of-thread
    48→// so it never blocks the UI.
    49→const queryPersister = createAsyncStoragePersister({
    50→  storage: indexedDBStorage,
    51→  // Only persist real string payloads (the persister sometimes asks us to
    52→  // store undefined for empty caches — skipping is harmless and faster).
    53→  throttleTime: 0, // write immediately — ensures offline-created entries survive process death before the 1-second window
    54→  key: 'rq-cache-v1',
    55→});
    56→
    57→interface DataContextType {
    58→  useParties: (userId: string) => {
    59→    data: Party[];
    60→    isLoading: boolean;
    61→    isFetching: boolean;
    62→    refetch: () => void;
    63→    setData: (updater: (old: Party[]) => Party[]) => void;
    64→  };
    65→  useInventory: (userId: string) => {
    66→    data: InventoryItem[];
    67→    isLoading: boolean;
    68→    isFetching: boolean;
    69→    refetch: () => void;
    70→    setData: (updater: (old: InventoryItem[]) => InventoryItem[]) => void;
    71→  };
    72→  useLowStockItems: (userId: string) => {
    73→    data: InventoryItem[];
    74→    isLoading: boolean;
    75→  };
    76→  useTransactions: (userId: string) => {
    77→    data: any[];
    78→    isLoading: boolean;
    79→    refetch: () => void;
    80→    setData: (updater: (old: any[]) => any[]) => void;
    81→  };
    82→  useLedger: (userId: string) => {
    83→    data: any[];
    84→    isLoading: boolean;
    85→    refetch: () => void;
    86→    setData: (updater: (old: any[]) => any[]) => void;
    87→  };
    88→  useExpenses: (userId: string) => {
    89→    data: any[];
    90→    isLoading: boolean;
    91→    refetch: () => void;
    92→    setData: (updater: (old: any[]) => any[]) => void;
    93→  };
    94→  useWaste: (userId: string) => {
    95→    data: WasteEntry[];
    96→    isLoading: boolean;
    97→    refetch: () => void;
    98→    setData: (updater: (old: WasteEntry[]) => WasteEntry[]) => void;
    99→  };
   100→  invalidateAll: (userId: string) => void;
   101→}
   102→
   103→const DataContext = createContext<DataContextType | null>(null);
   104→
   105→// Hooks for cached data access
   106→const usePartiesQuery = (userId: string) => {
   107→  return useQuery({
   108→    queryKey: ['parties', userId],
   109→    queryFn: async () => {
   110→      if (!userId) return [];
   111→      const snap = await ApiService.getAll(userId, 'parties');
   112→      return snap.docs.map(d => ({ id: d.id, ...d.data() })) as Party[];
   113→    },
   114→    enabled: !!userId,
   115→    staleTime: STALE.LONG,
   116→  });
   117→};
   118→
   119→const useInventoryQuery = (userId: string) => {
   120→  return useQuery({
   121→    queryKey: ['inventory', userId],
   122→    queryFn: async () => {
   123→      if (!userId) return [];
   124→      const snap = await ApiService.getAll(userId, 'inventory');
   125→      return snap.docs.map(d => ({ id: d.id, ...d.data() })) as InventoryItem[];
   126→    },
   127→    enabled: !!userId,
   128→    staleTime: STALE.MEDIUM,
   129→  });
   130→};
   131→
   132→const useTransactionsQuery = (userId: string) => {
   133→  return useQuery({
   134→    queryKey: ['transactions', userId],
   135→    queryFn: async () => {
   136→      if (!userId) return [];
   137→      const snap = await ApiService.getAll(userId, 'transactions');
   138→      const data = snap.docs.map(d => ({ id: d.id, ...d.data() })) as any[];
   139→      data.sort((a, b) => parseDateSafe(b.date).getTime() - parseDateSafe(a.date).getTime());
   140→      return data;
   141→    },
   142→    enabled: !!userId,
   143→    staleTime: STALE.SHORT,
   144→  });
   145→};
   146→
   147→const useLedgerQuery = (userId: string) => {
   148→  return useQuery({
   149→    queryKey: ['ledger', userId],
   150→    queryFn: async () => {
