   325→  // Stable object reference — hooks are module-level functions so this never changes.
   326→  // useMemo avoids re-creating the object on every DataProvider render.
   327→  const value = useMemo<DataContextType>(() => ({
   328→    useParties,
   329→    useInventory,
   330→    useLowStockItems,
   331→    useTransactions,
   332→    useLedger,
   333→    useExpenses,
   334→    useWaste,
   335→    invalidateAll,
   336→  }), []);
   337→
   338→  return (
   339→    <PersistQueryClientProvider
   340→      client={queryClient}
   341→      persistOptions={{
   342→        persister: queryPersister,
   343→        maxAge: CACHE_MAX_AGE,
   344→        // Bump this when you change a query's shape so old cached payloads
   345→        // from the previous version are dropped on cold start instead of
   346→        // being rehydrated into incompatible components.
   347→        buster: 'shopkeeper-v1',
   348→        dehydrateOptions: {
   349→          // Don't persist failed/loading queries — only successful ones.
   350→          // (Persisting an error state would replay it on cold start.)
   351→          shouldDehydrateQuery: q => q.state.status === 'success',
   352→        },
   353→      }}
   354→    >
   355→      <DataContext.Provider value={value}>
   356→        <DataErrorToastBridge />
   357→        {children}
   358→      </DataContext.Provider>
   359→    </PersistQueryClientProvider>
   360→  );
   361→};
   362→
   363→export const useData = () => {
   364→  const context = useContext(DataContext);
   365→  if (!context) throw new Error('useData must be used within DataProvider');
   366→  return context;
   367→};
   368→
   369→// Export query client for manual invalidation
   370→export { queryClient };
