    14→// Generic optimistic add mutation
    15→export function useOptimisticAdd<T extends { id?: string }>({
    16→  userId,
    17→  collection,
    18→  queryKey,
    19→  onSuccess,
    20→  onError
    21→}: OptimisticMutationOptions<T>) {
    22→  const queryClient = useQueryClient();
    23→
    24→  return useMutation({
    25→    mutationFn: async (newItem: Omit<T, 'id'>) => {
    26→      const payload = { ...newItem, created_at: new Date().toISOString() } as Record<string, any>;
    27→      if (!navigator.onLine) {
    28→        // Route through the durable sync queue so the entry survives reconnect.
    29→        // Return a stable offline ID so the optimistic cache entry persists
    30→        // through app restarts (no rollback — onError is never reached).
    31→        const offlineId = `offline_${Date.now()}_${Math.random().toString(36).slice(2, 9)}`;
    32→        SyncQueueService.addToQueue(userId, 'create', collection, payload);
    33→        return { id: offlineId, ...payload } as unknown as T;
    34→      }
    35→      const docRef = await ApiService.add(userId, collection, payload);
    36→      return { id: docRef.id, ...newItem } as unknown as T;
    37→    },
    38→    // Optimistic update
    39→    onMutate: async (newItem) => {
    40→      // Cancel outgoing refetches
    41→      await queryClient.cancelQueries({ queryKey });
    42→
    43→      // Snapshot previous value
    44→      const previousData = queryClient.getQueryData<T[]>(queryKey);
    45→
    46→      // Optimistically update with temp ID
    47→      const tempId = `temp_${Date.now()}`;
    48→      queryClient.setQueryData<T[]>(queryKey, (old = []) => [
    49→        { id: tempId, ...newItem, created_at: new Date().toISOString() } as unknown as T,
    50→        ...old
    51→      ]);
    52→
    53→      haptic.light();
    54→
    55→      return { previousData, tempId };
    56→    },
    57→    // On error, rollback
    58→    onError: (err, _newItem, context) => {
    59→      if (context?.previousData) {
    60→        queryClient.setQueryData(queryKey, context.previousData);
    61→      }
    62→      haptic.error();
    63→      onError?.(err as Error);
    64→    },
    65→    // On success, replace temp with real ID
    66→    onSuccess: (data, _variables, context) => {
    67→      queryClient.setQueryData<T[]>(queryKey, (old = []) =>
    68→        old.map(item => (item.id === context?.tempId ? data : item))
    69→      );
    70→      haptic.success();
    71→      onSuccess?.();
    72→    },
    73→    onSettled: () => {
    74→      // Refetch to ensure sync
    75→      queryClient.invalidateQueries({ queryKey });
    76→    }
    77→  });
    78→}
