   169→  if (now <= endDate.toMillis()) return rawStatus; // still valid
   170→  const graceEnd = graceEndDate?.toMillis() ?? (endDate.toMillis() + gracePeriodMs);
   171→  if (now <= graceEnd) return 'grace';
   172→  return 'expired';
   173→}
   174→
   175→/**
   176→ * Determine if a subscription is currently in its grace period.
   177→ * Accepts both 'grace' (Firestore-stored) and 'expired' (computed) statuses.
   178→ */
   179→function computeGrace(
   180→  endDate:      Timestamp | null,
   181→  graceEndDate: Timestamp | null | undefined,
   182→  status:       SubscriptionStatus,
   183→  gracePeriodMs: number,
   184→): boolean {
   185→  if (status === 'grace') return true;
   186→  if (status !== 'expired') return false;
   187→  const now = Date.now();
   188→  if (graceEndDate) return now <= graceEndDate.toMillis();
   189→  if (!endDate) return false;
   190→  return (now - endDate.toMillis()) <= gracePeriodMs;
   191→}
