   193→// ── normalizeDoc ──────────────────────────────────────────────────────────────
   194→// Converts a raw Firestore data object into a typed Subscription.
   195→// Handles both legacy docs (only `plan` field) and v2 docs (have `planId`).
   196→
   197→function normalizeDoc(data: Record<string, any>, gracePeriodMs: number = GRACE_PERIOD_MS): Subscription {
   198→  const endDate      = rehydrateTimestamp(data.endDate);
   199→  const graceEndDate = rehydrateTimestamp(data.graceEndDate);
   200→  const rawStatus    = (data.status as SubscriptionStatus) ?? 'active';
   201→  const status       = computeStatus(endDate, graceEndDate, rawStatus, gracePeriodMs);
   202→  return {
   203→    plan:         (data.plan ?? data.planId ?? 'free') as SubscriptionPlan,
   204→    planId:       data.planId ?? data.plan ?? 'free',
   205→    status,
   206→    startDate:    rehydrateTimestamp(data.startDate),
   207→    endDate,
   208→    graceEndDate,
   209→    trialUsed:    data.trialUsed   ?? false,
   210→    autoRenew:    data.autoRenew   ?? false,
   211→    paymentId:    data.paymentId   ?? null,
   212→    source:       data.source      ?? 'system',
   213→    introOffer:   data.introOffer,
   214→    createdAt:    rehydrateTimestamp(data.createdAt),
   215→    updatedAt:    rehydrateTimestamp(data.updatedAt),
   216→  };
   217→}
