   335→/**
   336→ * Format number as INR currency
   337→ */
   338→function fmtINR(amount: number): string {
   339→  const abs = Math.abs(Number(amount || 0));
   340→  const [intPart, decPart] = abs.toFixed(2).split('.');
   341→  let formatted = '';
   342→  if (intPart.length <= 3) {
   343→    formatted = intPart;
   344→  } else {
   345→    formatted = intPart.slice(-3);
   346→    let rest = intPart.slice(0, -3);
   347→    while (rest.length > 2) {
   348→      formatted = rest.slice(-2) + ',' + formatted;
   349→      rest = rest.slice(0, -2);
   350→    }
   351→    if (rest.length > 0) formatted = rest + ',' + formatted;
   352→  }
   353→  return `Rs.${formatted}.${decPart}`;
   354→}
   355→
   356→/**
   357→ * Convert amount to words — Indian number system (crore/lakh/thousand)
   358→ */
   359→function amountInWords(amount: number): string {
   360→  if (!isFinite(amount) || isNaN(amount)) return 'Amount in words: N/A';
   361→
   362→  const ONES = [
   363→    '', 'One', 'Two', 'Three', 'Four', 'Five', 'Six', 'Seven', 'Eight', 'Nine',
   364→    'Ten', 'Eleven', 'Twelve', 'Thirteen', 'Fourteen', 'Fifteen', 'Sixteen',
   365→    'Seventeen', 'Eighteen', 'Nineteen',
   366→  ];
   367→  const TENS = ['', '', 'Twenty', 'Thirty', 'Forty', 'Fifty', 'Sixty', 'Seventy', 'Eighty', 'Ninety'];
   368→
   369→  function twoDigits(n: number): string {
   370→    if (n === 0) return '';
   371→    if (n < 20) return ONES[n];
   372→    return TENS[Math.floor(n / 10)] + (n % 10 ? ' ' + ONES[n % 10] : '');
   373→  }
   374→
   375→  function threeDigits(n: number): string {
   376→    if (n === 0) return '';
   377→    if (n < 100) return twoDigits(n);
   378→    return ONES[Math.floor(n / 100)] + ' Hundred' + (n % 100 ? ' ' + twoDigits(n % 100) : '');
   379→  }
   380→
   381→  const absAmt = Math.abs(amount);
   382→  const rupees = Math.floor(absAmt);
   383→  const paise  = Math.round((absAmt - rupees) * 100);
   384→
   385→  if (rupees === 0 && paise === 0) return 'Zero Rupees Only';
   386→
   387→  const crore   = Math.floor(rupees / 10_000_000);
   388→  const lakh    = Math.floor((rupees % 10_000_000) / 100_000);
   389→  const thousand = Math.floor((rupees % 100_000) / 1_000);
   390→  const rem     = rupees % 1_000;
   391→
   392→  const parts: string[] = [];
   393→  if (crore   > 0) parts.push(threeDigits(crore)   + ' Crore');
   394→  if (lakh    > 0) parts.push(twoDigits(lakh)       + ' Lakh');
   395→  if (thousand > 0) parts.push(twoDigits(thousand)  + ' Thousand');
   396→  if (rem     > 0) parts.push(threeDigits(rem));
   397→
   398→  const prefix = amount < 0 ? 'Minus ' : '';
   399→  let result = prefix + 'Rupees ' + parts.join(' ') + ' Only';
   400→  if (paise > 0) result += ` and ${twoDigits(paise)} Paise`;
   401→  return result;
   402→}

