    25→// swallow any rejection (AuditService.log already swallows internally, but the
    26→// outer await was still forcing a serial round-trip).
    27→function auditAsync(...args: Parameters<typeof AuditService.log>) {
    28→  AuditService.log(...args).catch(() => { /* intentionally swallowed */ });
    29→}
    30→
    31→/**
    32→ * WRITE TIMEOUT GUARD
    33→ * ─────────────────────────────────────────────────────────────────────────────
    34→ * With persistentLocalCache, every Firestore write lands in local IndexedDB
    35→ * and resolves in < 100 ms regardless of network state.  This timeout now acts
    36→ * as a last-resort sentinel for a genuine IndexedDB lock freeze (e.g. storage
    37→ * quota exceeded, corrupted database).  Under normal conditions it should never
    38→ * fire.  8 s is a generous allowance for first-launch IndexedDB initialisation
    39→ * while being short enough that a real freeze doesn't block the UI for long.
    40→ */
    41→const WRITE_TIMEOUT_MS = 8_000;
    42→
    43→function withWriteTimeout<T>(promise: Promise<T>): Promise<T> {
    44→  return Promise.race([
    45→    promise,
    46→    new Promise<T>((_, reject) =>
    47→      setTimeout(() => {
    48→        const err: any = new Error(
    49→          'Save timed out — queued for background sync.',
    50→        );
    51→        err.code = 'WRITE_TIMEOUT';
    52→        reject(err);
    53→      }, WRITE_TIMEOUT_MS),
    54→    ),
    55→  ]);
    56→}
