    58→/**
    59→ * Recursively removes undefined values from an object so Firestore never
    60→ * receives `undefined` fields (which it rejects with an error).
    61→ */
    62→function sanitizeForFirestore(obj: any): any {
    63→  if (obj === null || obj === undefined) return obj;
    64→  if (Array.isArray(obj)) return obj.map(sanitizeForFirestore);
    65→  if (typeof obj === 'object' && !(obj instanceof Date)) {
    66→    return Object.fromEntries(
