    57→// ── Truncate string to fit maxW with '…' suffix ─────────────────────────────
    58→function trunc(s: string, maxW: number, sz: number): string {
    59→  if (strW(s, sz) <= maxW) return s;
    60→  const sfx = '...';
    61→  const sw = strW(sfx, sz);
    62→  let r = '';
    63→  for (const c of s) {
    64→    if (strW(r + c, sz) + sw > maxW) break;
    65→    r += c;
    66→  }
    67→  return r + sfx;
    68→}
    69→
    70→// ── Word-wrap text into lines that fit within maxW ───────────────────────────
    71→function wrap(text: string, maxW: number, sz: number): string[] {
    72→  if (!text.trim()) return [''];
    73→  const words = text.split(/\s+/);
    74→  const lines: string[] = [];
    75→  let cur = '';
    76→  for (const w of words) {
    77→    const test = cur ? cur + ' ' + w : w;
    78→    if (strW(test, sz) <= maxW) { cur = test; }
    79→    else {
    80→      if (cur) lines.push(cur);
    81→      cur = strW(w, sz) > maxW ? trunc(w, maxW, sz) : w;
    82→    }
    83→  }
    84→  if (cur) lines.push(cur);
    85→  return lines.length ? lines : [''];
    86→}
