capturedCommit()
  .then(() => {
    if (_doInvRefresh) {
      // Optimistically apply inventory changes to the TanStack Query cache
      // immediately after the IndexedDB write. This makes the corrected
      // stock values visible to the NEXT modal open without waiting for the
      // async Firestore getDocs round-trip from refetchInventory().
      // Critical for rapid back-to-back offline saves where the second
      // modal opens before the first refetch has completed.
      setInventoryData(old => {
        let updated = [...old];
        _batchOpsSnap.forEach((op, idx) => {
          if (op.col !== 'inventory') return;
          if (op.type === 'add') {
            const newId = _batchResultsSnap[idx]?.id;
            if (newId && !updated.some(i => i.id === newId)) {
              updated = [{ id: newId, ...op.data }, ...updated];
            }
          } else if (op.type === 'update' && op.id) {
            const itemIdx = updated.findIndex(i => i.id === op.id);
            if (itemIdx >= 0) updated[itemIdx] = { ...updated[itemIdx], ...op.data };
          }
        });
        return updated;
      });
      // Also trigger a background refetch to sync with Firestore local cache
      // (catches any edge-cases where the optimistic update missed something).
      refetchInventory();
    }

    // Link the auto-added party's ID back into the entry (best-effort)
    if (_autoPartyLink) {
      ApiService.update(_uid, _autoPartyLink.col, _autoPartyLink.entryId,
        { party_id: _autoPartyLink.partyId }).catch(() => {});
    }

    // Party cascade: update all denormalized copies in related collections.
    // Runs AFTER commit so Firestore's local cache already has the updated
    // party doc before we query ledger_entries / transactions.
    if (_cascade) {
      syncPartyToRecords(_uid, _cascade.partyId, _cascade.oldName, _cascade.fields)
        .then(n => {
          if (n > 0)
            showToast(`Updated ${n} linked record${n !== 1 ? 's' : ''}`, 'info');
          refetchLedger();
          refetchTransactions();
        })
        .catch(e => console.error('[partySync] cascade failed:', e));
    }
  })
  .catch(err => {
    console.error('[ManualEntryModal] bg write failed:', err);
    // DUPLICATE PREVENTION: only route to SyncQueue when the device is
    // genuinely offline. With memoryLocalCache the Firestore SDK keeps
    // the batch in its own in-memory queue and retries it automatically
    // when connectivity is restored. If we ALSO add the ops to SyncQueue
    // here, both paths eventually write to Firestore → duplicate documents.
    // When offline, the SDK has no persistence across restarts, so the
    // SyncQueue is still needed as the durable fallback.
    if (!navigator.onLine) {
      for (const op of _batchOpsSnap) {
        SyncQueueService.addToQueue(
          _uid,
          op.type === 'add' ? 'create' : 'update',
          op.col, op.data, op.id,
        );
      }
      setTimeout(() => SyncQueueService.processQueue(_uid).catch(() => {}), 1000);
    }
  });

