        const ref = doc(db, `users/${uid}/${op.col}`, op.id);
        batch.update(ref, sanitizeForFirestore(op.data));
        chunkResults.push({ type: 'update', id: op.id });
      }
    }
    await withWriteTimeout(batch.commit());
    allResults.push(...chunkResults);
